// Ambil data output dari node AI Agent
const rawOutput = $input.first().json.output;

// 1. Ekstrak Subjek (Mencari teks setelah "Subjek:" hingga baris baru)
const subjectMatch = rawOutput.match(/Subjek:\s*(.*)/i);
const subject = subjectMatch ? subjectMatch[1].trim() : "";

// 2. Hapus bagian Subjek dari teks utama untuk mempermudah pemisahan sisanya
let bodyText = rawOutput.replace(/Subjek:.*\n*/i, "").trim();

// 3. Pisahkan bagian-bagian berdasarkan baris kosong (\n\n)
const paragraphs = bodyText.split(/\n\s*\n/);

// 4. Identifikasi bagian (Contoh pembagian sederhana)
const greeting = paragraphs[0]; // "Halo Rafi,"
const opening = paragraphs[1];  // "Terima kasih atas minat..."
const coreMessage = paragraphs[2]; // "Mengenai permintaan Anda..."

// 5. Ekstrak daftar pertanyaan (Mencari baris yang dimulai dengan *)
const questionsMatch = bodyText.match(/\*\s*(.*)/g);
const questions = questionsMatch ? questionsMatch.join("\n") : "";

// 6. Ambil salam penutup (biasanya 2 paragraf terakhir)
const closing = paragraphs[paragraphs.length - 2];
const signOff = paragraphs[paragraphs.length - 1];

return {
  subject: subject,
  greeting: greeting,
  opening: opening,
  message_content: coreMessage,
  questions: questions,
  closing: closing,
  sign_off: signOff,
  full_clean_body: bodyText
};

// Ambil data dari node sebelumnya
const raw = $input.first().json.output;

if (!raw) {
  return [{
    json: {
      intent: "HUMAN_REVIEW",
      urgency: "LOW",
      sentiment: "NEUTRAL",
      budget_detected: false,
      priority_signal: "HUMAN_REVIEW",
      confidence_score: 0,
      error: "Empty AI output"
    }
  }];
}

let parsed;

// Jika sudah object (bukan string), langsung pakai
if (typeof raw === "object") {
  parsed = raw;
} else {
  // Jika string, ambil hanya bagian JSON-nya
  const match = raw.match(/\{[\s\S]*\}/);

  if (!match) {
    return [{
      json: {
        intent: "HUMAN_REVIEW",
        urgency: "LOW",
        sentiment: "NEUTRAL",
        budget_detected: false,
        priority_signal: "HUMAN_REVIEW",
        confidence_score: 0,
        error: "No valid JSON found"
      }
    }];
  }

  try {
    parsed = JSON.parse(match[0]);
  } catch (err) {
    return [{
      json: {
        intent: "HUMAN_REVIEW",
        urgency: "LOW",
        sentiment: "NEUTRAL",
        budget_detected: false,
        priority_signal: "HUMAN_REVIEW",
        confidence_score: 0,
        error: "Invalid JSON format"
      }
    }];
  }
}

// Return clean structured data
return [{
  json: {
    intent: parsed.intent || "HUMAN_REVIEW",
    urgency: parsed.urgency || "LOW",
    sentiment: parsed.sentiment || "NEUTRAL",
    budget_detected: parsed.budget_detected ?? false,
    priority_signal: parsed.priority_signal || "HUMAN_REVIEW",
    confidence_score: parsed.confidence_score ?? 0
  }
}];

